import{_ as o,o as a,c as r,a2 as t}from"./chunks/framework.IwO0Hdn_.js";const p=JSON.parse('{"title":"[LOGIC / BUSINESS] F-04.9 — Borrar Entrada del Histórico","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-04.9_borrar_historico.md","filePath":"backlog/F-04.9_borrar_historico.md","lastUpdated":null}'),i={name:"backlog/F-04.9_borrar_historico.md"};function s(n,e,c,d,l,u){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="logic-business-f-04-9-—-borrar-entrada-del-historico" tabindex="-1">[LOGIC / BUSINESS] F-04.9 — Borrar Entrada del Histórico <a class="header-anchor" href="#logic-business-f-04-9-—-borrar-entrada-del-historico" aria-label="Permalink to &quot;[LOGIC / BUSINESS] F-04.9 — Borrar Entrada del Histórico&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-04 — Histórico de Logs Archivados</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Logic / Business</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-04.1_vista_historico_pestana.html">F-04.1</a></td><td>Componente Livewire <code>ArchivedLogDetail</code> donde se añade el botón &#39;Borrar&#39;</td></tr><tr><td><a href="./F-05.5_usuarios_mock_session.html">F-05.5</a></td><td>Usuario autenticado y políticas de autorización disponibles</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Could</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero poder borrar una entrada del histórico de logs Para eliminar registros archivados por error o que ya no son relevantes para el seguimiento</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Borrar con confirmación):</strong> Dado que estoy en el detalle de un log archivado, cuando pulso &quot;Borrar&quot; (botón visible en la vista histórico), entonces se muestra un modal de confirmación (Alpine.js <code>x-show</code>) antes de proceder.</li><li>[ ] <strong>Escenario 2 (Borrado en cascada):</strong> Dado que confirmo el borrado, cuando se ejecuta la acción, entonces se borra la entrada de <code>archived_logs</code> y todos sus <code>comments</code> asociados (CASCADE en FK). El log original en la tabla <code>logs</code> NO se recupera (el campo <code>archived</code> permanece <code>true</code>).</li><li>[ ] <strong>Escenario 3 (Botón solo en Histórico):</strong> Dado que consulto el detalle de un log activo, cuando se carga la vista, entonces NO existe botón &quot;Borrar&quot; — esta acción es exclusiva de la vista histórico.</li><li>[ ] <strong>Escenario 4 (Redirección post-borrado):</strong> Dado que el borrado se completa, cuando finaliza, entonces el usuario es redirigido a la lista del histórico (<code>/historico</code>) con un flash message &quot;Entrada eliminada correctamente&quot;.</li><li>[ ] <strong>Requisito Técnico:</strong> Livewire Action <code>deleteArchivedLog(id)</code> en <code>ArchivedLogDetail</code>. Ejecuta <code>$archivedLog-&gt;delete()</code> (Eloquent con cascade). Middleware <code>auth</code> verifica sesión activa. NO se elimina el registro original de <code>logs</code>.</li></ul><hr><p><strong>MoSCoW:</strong> <code>COULD</code><strong>Sprint:</strong> Sprint 4</p><p><strong>Notas:</strong></p><ul><li>El borrado del histórico es una acción de administración excepcional. La operación normal es dejar el histórico crecer indefinidamente.</li><li>Se registra en el log de aplicación (Laravel Log) quién y cuándo borró una entrada (NFR-OBS-02).</li></ul>',16)])])}const h=o(i,[["render",s]]);export{p as __pageData,h as default};
